using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any type.
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing.
//    With the default resolver every type is resolvable, so Person succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? tryInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Person> => resolved ({tryInfo!.Type.Name})");
}

// Now demonstrate the "not available" branch.
// A source-gen context that only knows about Person — int[] is NOT included.
var limited = new JsonSerializerOptions { TypeInfoResolver = LimitedContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int[]> => resolved ({arrayInfo!.Type.Name})");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> => not available (no exception thrown)");
}

// -- types ----------------------------------------------------------------

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
internal partial class LimitedContext : JsonSerializerContext;

